#!/usr/bin/env node
/**
 * Scan on-arrival assignments in .dry scenes (outside {! !}) and ensure each
 * stack id has a placeholder row in Q.electorateModifierCatalog (delta 0).
 *
 * Usage:
 *   node scripts/sync-electorate-modifiers.js
 *   node scripts/sync-electorate-modifiers.js --check   # exit 1 if updates needed
 *   node scripts/sync-electorate-modifiers.js --dry-run
 */

const fs = require('fs')
const path = require('path')

const ROOT = path.join(__dirname, '..')
const SOURCE_DIR = path.join(ROOT, 'source', 'scenes')
const CATALOG_FILE = path.join(ROOT, 'source', 'scenes', 'post_event.scene.dry')

const SCOPES = new Set(['stratum', 'district', 'global'])
const PARTY_KEYS = new Set(['D', 'I', 'C', 'G', 'H'])
const AUTO_MARKER = '// --- auto-synced electorate stacks (delta 0) ---'
const REF_MARKER = '// --- Reference only:'

const RESERVED = new Set([
    'if', 'and', 'or', 'not', 'true', 'false', 'TBD',
    'Q', 'window', 'typeof', 'return', 'function', 'var', 'new',
])

/** Story stacks are usually bumped with += / -= on arrival. */
const STACK_ASSIGN_RE = /(?:^|[;,\s]+)([a-z][a-z0-9_]*)\s*(?:\+=|-=)/gi

const EXCLUDE_NAMES = new Set([
    'month_actions',
    'next_election_month',
    'next_election_year',
    'next_election_time',
    'phase',
    'organizing_unlock',
    'coalition_dissent',
    'shuffle_cabinet_timer',
])

function walkDryFiles(dir, out = []) {
    for (const ent of fs.readdirSync(dir, { withFileTypes: true })) {
        const p = path.join(dir, ent.name)
        if (ent.isDirectory()) {
            walkDryFiles(p, out)
        } else if (ent.name.endsWith('.dry')) {
            out.push(p)
        }
    }
    return out
}

/** Strip {! ... !} regions; return prose/on-arrival-safe text. */
function stripMagicBlocks(text) {
    return text.replace(/\{![\s\S]*?\!}/g, ' ')
}

function extractAssignmentTargets(text) {
    const found = new Set()
    let m
    const re = new RegExp(ASSIGN_RE.source, 'gi')
    while ((m = re.exec(text)) !== null) {
        const name = m[1]
        if (RESERVED.has(name)) { continue }
        if (name.endsWith('_TBD')) { continue }
        found.add(name)
    }
    return found
}

function extractStacksFromOnArrival(filePath) {
    const text = fs.readFileSync(filePath, 'utf8')
    const lines = text.split(/\r?\n/)
    const stacks = new Set()

    for (const line of lines) {
        const trimmed = line.trim()
        if (!/^on-arrival:/i.test(trimmed)) { continue }
        const payload = trimmed.replace(/^on-arrival:\s*/i, '')
        if (!payload || /^\{!/.test(payload)) { continue }
        const bare = stripMagicBlocks(payload)
        for (const name of extractAssignmentTargets(bare)) {
            stacks.add(name)
        }
    }
    return stacks
}

function parseStackIdFromLine(line) {
    const parts = [...line.matchAll(/'([^']*)'/g)].map((m) => m[1])
    if (parts.length < 2) { return null }
    if (SCOPES.has(parts[1])) { return parts[0] }
    if (parts.length >= 3 && SCOPES.has(parts[2])) { return parts[1] }
    return parts[0]
}

function parseCatalogStackIds(catalogText) {
    const active = catalogText.split(REF_MARKER)[0]
    const ids = new Set()
    for (const line of active.split(/\r?\n/)) {
        if (!line.includes('new ElectorateModifier')) { continue }
        const stackId = parseStackIdFromLine(line)
        if (stackId) { ids.add(stackId) }
    }
    return ids
}

function formatPlaceholder(stackId) {
    return `    new ElectorateModifier('${stackId}_auto', '${stackId}', 'global', '', 'D', 0),`
}

function upsertCatalog(newStacks) {
    const text = fs.readFileSync(CATALOG_FILE, 'utf8')
    const existing = parseCatalogStackIds(text)
    const missing = [...newStacks].filter((s) => !existing.has(s)).sort()
    if (missing.length === 0) {
        return { changed: false, missing: [], text }
    }

    const lines = missing.map((s) => formatPlaceholder(s))
    let updated = text

    if (updated.includes(AUTO_MARKER)) {
        const insertAt = updated.indexOf(AUTO_MARKER) + AUTO_MARKER.length
        updated =
            updated.slice(0, insertAt)
            + '\n'
            + lines.join('\n')
            + updated.slice(insertAt)
    } else {
        const anchor = REF_MARKER
        const idx = updated.indexOf(anchor)
        const block =
            '\n\n    '
            + AUTO_MARKER
            + '\n'
            + lines.join('\n')
            + '\n'
        if (idx !== -1) {
            updated = updated.slice(0, idx) + block + updated.slice(idx)
        } else {
            updated = updated.replace(
                /(\n\])\s*(\n\nQ\.applyElectorateModifiers)/,
                block + '\n$1$2'
            )
        }
    }

    return { changed: true, missing, text: updated }
}

function collectAllStacks() {
    const files = walkDryFiles(SOURCE_DIR).filter(
        (f) => path.normalize(f) !== path.normalize(CATALOG_FILE)
    )
    const all = new Set()
    for (const file of files) {
        for (const s of extractStacksFromOnArrival(file)) {
            all.add(s)
        }
    }
    return all
}

function main() {
    const check = process.argv.includes('--check')
    const dryRun = process.argv.includes('--dry-run')
    const stacks = collectAllStacks()
    const { changed, missing, text } = upsertCatalog(stacks)

    if (missing.length === 0) {
        console.log('electorate stacks: catalog is up to date')
        process.exit(0)
    }

    console.log(`electorate stacks: adding ${missing.length} placeholder(s):`)
    for (const s of missing) {
        console.log(`  - ${s}`)
    }

    if (check) {
        process.exit(1)
    }
    if (!dryRun) {
        fs.writeFileSync(CATALOG_FILE, text, 'utf8')
        console.log(`updated ${path.relative(ROOT, CATALOG_FILE)}`)
    }
    process.exit(0)
}

main()

