    var state = Q.electionV2
    if (!state) { return }

    state.demographicsById = state.demographicsById || Object.fromEntries(
        state.demographics.map(function(d) { return [d.id, d] })
    )
    state.districtsById = state.districtsById || Object.fromEntries(
        state.districts.map(function(d) { return [d.id, d] })
    )

    for (var i = 0; i < state.demographics.length; i++) {
        var dem = state.demographics[i]
        dem.competitiveScores = electorateCopyScores(
            dem._baseCompetitiveScores || dem.competitiveScores
        )
    }
    for (var j = 0; j < state.districts.length; j++) {
        var dist = state.districts[j]
        dist.competitiveScores = electorateCopyScores(
            dist._baseCompetitiveScores || dist.competitiveScores
        )
    }
    state.global.competitiveScores = electorateCopyScores(
        state._baseGlobalScores || state.global.competitiveScores
    )

    for (var m = 0; m < Q.electorateModifierCatalog.length; m++) {
        Q.electorateModifierCatalog[m].apply(state, Q)
    }
}

